INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？", 3001, 2, 1, 7, 4.74, 9, "vo_minigame_1012_result_1079", 0, 5, 1, 1, 12300147);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 3001, 2, 1, 1, 0.0, 9, "vo_minigame_1012_result_1080", 0, 5, 1, 1, 12300148);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 3001, 2, 1, 8, 2.21, 9, "vo_minigame_1012_result_1081", 0, 5, 1, 2, 12300149);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 3001, 2, 1, 3, 2.46, 9, "vo_minigame_1012_result_1082", 0, 5, 1, 2, 12300150);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 3001, 2, 1, 3, 2.94, 9, "vo_minigame_1012_result_1083", 0, 5, 1, 2, 12300151);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 3001, 2, 1, 7, 4.19, 9, "vo_minigame_1012_result_1084", 0, 5, 1, 3, 12300152);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 3001, 2, 1, 1, 0.0, 9, "vo_minigame_1012_result_1085", 0, 5, 1, 3, 12300153);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 3001, 2, 1, 3, 2.63, 9, "vo_minigame_1012_result_1086", 0, 5, 1, 3, 12300154);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 3001, 2, 1, 3, 5.53, 4, "vo_minigame_1012_result_1087", 0, 1, 1, 1, 12300155);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 3001, 2, 3, 3, 0.01, 4, "vo_minigame_1012_result_1088", 9, 1, 1, 1, 12300156);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 3001, 2, 1, 3, 4.15, 4, "vo_minigame_1012_result_1089", 3, 1, 1, 1, 12300157);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 3001, 2, 9, 9, 0.01, 4, "vo_minigame_1012_result_1090", 9, 1, 1, 2, 12300158);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 3001, 2, 1, 3, 5.37, 4, "vo_minigame_1012_result_1091", 0, 1, 1, 2, 12300159);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 3001, 2, 1, 3, 1.44, 4, "vo_minigame_1012_result_1092", 0, 1, 1, 2, 12300160);
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES ("んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 3001, 2, 3, 3, 0.0, 4, "vo_minigame_1012_result_1093", 0, 1, 1, 3, 12300161);
